function StarsRow({ value = 5, size = 16 }: { value?: number; size?: number }) {
  return (
    <div className="flex gap-0.5 text-brand-gold">
      {[...Array(5)].map((_, i) => (
        <StarIcon key={i} size={size} style={{ opacity: i < Math.round(value) ? 1 : 0.25 }} />
      ))}
    </div>
  );
}

function ScrollingBanner({ items, bg, color }: { items: string[]; bg: string; color: string }) {
  const doubled = [...items, ...items, ...items];
  return (
    <div className="overflow-hidden py-3" style={{ background: bg, color }}>
      <div className="flex animate-scroll-x whitespace-nowrap gap-12 text-sm font-semibold tracking-wide">
        {doubled.map((t, i) => (
          <span key={i} className="flex items-center gap-3">
            <SparkleIcon size={14} />
            {t}
          </span>
        ))}
      </div>
    </div>
  );
}

function useCountdown(initial: { d: number; h: number; m: number; s: number }) {
  const [t, setT] = useState(initial);
  useEffect(() => {
    const id = setInterval(() => {
      setT((prev) => {
        let { d, h, m, s } = prev;
        s--;
        if (s < 0) { s = 59; m--; }
        if (m < 0) { m = 59; h--; }
        if (h < 0) { h = 23; d--; }
        if (d < 0) { d = 0; h = 0; m = 0; s = 0; }
        return { d, h, m, s };
      });
    }, 1000);
    return () => clearInterval(id);
  }, []);
  return t;
}

function CountdownBoxes({ d, h, m, s }: { d: number; h: number; m: number; s: number }) {
  const pad = (n: number) => n.toString().padStart(2, '0');
  const boxes = [
    { v: pad(d), l: 'DAYS' },
    { v: pad(h), l: 'HOURS' },
    { v: pad(m), l: 'MIN' },
    { v: pad(s), l: 'SEC' },
  ];
  return (
    <div className="flex gap-2 justify-center">
      {boxes.map((b) => (
        <div key={b.l} className="bg-brand-text text-white rounded-lg px-3 py-2 min-w-[62px] text-center">
          <div className="font-heading text-2xl font-bold leading-none">{b.v}</div>
          <div className="text-[10px] mt-1 tracking-widest opacity-90">{b.l}</div>
        </div>
      ))}
    </div>
  );
}

function scrollToPricing() {
  const el = document.getElementById('pricing');
  if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });
}

function scrollToId(id: string) {
  const el = document.getElementById(id);
  if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });
}

function CTAButton({ children, onClick, className = '' }: { children: React.ReactNode; onClick?: () => void; className?: string }) {
  return (
    <button
      onClick={onClick ?? scrollToPricing}
      className={`inline-flex items-center justify-center gap-2 bg-brand-accent hover:bg-brand-gold-dark transition-all duration-300 text-white font-bold px-8 py-4 rounded-md tracking-wide shadow-md hover:shadow-xl hover:-translate-y-0.5 ${className}`}
    >
      {children}
    </button>
  );
}

