function Header() {
  const h = LANDING.header;
  const [open, setOpen] = useState(false);
  const slugMap: Record<string, string> = {
    'RECURSOS': 'features', 'COMO USAR': 'how-to-use', 'AVALIAÇÕES': 'reviews', 'FAQ': 'faq', 'CONTATO': 'contact',
    'FEATURES': 'features', 'HOW TO USE': 'how-to-use', 'REVIEWS': 'reviews', 'CONTACT': 'contact',
  };
  return (
    <header className="bg-white border-b border-neutral-200 sticky top-0 z-40">
      <div className="max-w-7xl mx-auto px-4 lg:px-8 py-4 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 bg-brand-text text-white rounded flex items-center justify-center font-heading text-[11px] tracking-widest">{BRAND.monogram_badge}</div>
          <span className="font-heading text-xl md:text-2xl font-bold tracking-wide text-brand-text">{h.logo_text}</span>
        </div>
        <nav className="hidden md:flex items-center gap-8">
          {h.menu.map((label: string) => (
            <button
              key={label}
              onClick={() => scrollToId(slugMap[label] || label.toLowerCase())}
              className="text-xs font-semibold tracking-widest text-brand-text hover:text-brand-primary transition-colors cursor-pointer"
            >
              {label}
            </button>
          ))}
        </nav>
        <div className="flex items-center gap-4">
          <button onClick={scrollToPricing} className="text-brand-text hover:text-brand-primary transition-colors relative" aria-label="Cart">
            <CartIcon size={24} />
            <span className="absolute -top-1 -right-1 w-4 h-4 bg-brand-gold text-white text-[10px] rounded-full flex items-center justify-center font-bold">0</span>
          </button>
          <button className="md:hidden text-brand-text" onClick={() => setOpen(!open)} aria-label="Menu">
            <MenuIcon size={24} />
          </button>
        </div>
      </div>
      {open && (
        <div className="md:hidden border-t border-neutral-200 bg-white px-4 py-4 flex flex-col gap-3">
          {h.menu.map((label: string) => (
            <button
              key={label}
              onClick={() => { scrollToId(slugMap[label] || label.toLowerCase()); setOpen(false); }}
              className="text-sm font-semibold tracking-widest text-brand-text text-left"
            >
              {label}
            </button>
          ))}
        </div>
      )}
    </header>
  );
}

