// ═════════════════════════════════════════════════════════════════════════════
// Pricing Offer
// ═════════════════════════════════════════════════════════════════════════════

function PricingOffer() {
  const po = LANDING.pricing_offer_section;
  const cd = po.countdown || { days: 0, hours: 2, minutes: 47, seconds: 39 };
  const t = useCountdown({ d: cd.days || 0, h: cd.hours || 0, m: cd.minutes || 0, s: cd.seconds || 0 });
  return (
    <section id="pricing" className="py-16 md:py-24 bg-white scroll-mt-24">
      <div className="max-w-7xl mx-auto px-4 lg:px-8 text-center mb-10">
        <h2 className="font-heading text-3xl md:text-4xl lg:text-5xl font-bold text-brand-text mb-4 leading-tight">
          {po.title}
        </h2>
        <p className="text-brand-danger font-semibold mb-6">{po.urgency_text}</p>
        <CountdownBoxes d={t.d} h={t.h} m={t.m} s={t.s} />
      </div>
      <div className="max-w-7xl mx-auto px-4 lg:px-8 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-5">
        {po.tiers.map((tier: any) => {
          const isHighlighted = String(tier.label).toUpperCase().includes('BEST');
          const total = tier[PRICE_KEY] ?? tier.total_price_brl ?? tier.total_price_usd ?? 0;
          const orig = tier[ORIG_KEY] ?? tier.original_price_brl ?? tier.original_price_usd ?? 0;
          const per = tier[PER_KEY] ?? tier.price_per_unit_brl ?? tier.price_per_unit_usd ?? 0;
          return (
            <div key={tier.label} className={`relative rounded-xl overflow-hidden border-2 transition-all ${isHighlighted ? 'border-brand-primary shadow-2xl scale-[1.02]' : 'border-neutral-200 shadow-md'} bg-white flex flex-col`}>
              {isHighlighted && (
                <div className="absolute top-0 right-0 bg-brand-gold text-white text-[10px] font-bold px-3 py-1 tracking-wider">BEST SELLER</div>
              )}
              <div className={`py-2 text-center font-heading font-bold text-sm tracking-widest ${isHighlighted ? 'bg-brand-success text-white' : 'bg-brand-text text-white'}`}>
                {tier.label}
              </div>
              <div className="p-5 flex flex-col flex-1">
                <div className="flex items-center justify-center gap-2 mb-2">
                  <StarsRow value={4.9} size={14} />
                  <span className="text-xs text-brand-text-light">(4.9)</span>
                </div>
                {/* image_prompt assembled inline */}
                <div className="aspect-square bg-brand-bg rounded-lg mb-4 overflow-hidden">
                  <img
                    src={ph(400, 400, `${tier.quantity}x ${BRAND.name}`)}
                    alt={`${tier.quantity}x ${BRAND.name_with_tm}`}
                    data-image-prompt={`Premium product mockup of ${tier.quantity}x ${BRAND.name_with_tm} bottles, clean white background, soft professional product photography lighting, premium ecommerce campaign aesthetic.`}
                    className="w-full h-full object-cover bg-neutral-100"
                  />
                </div>
                <p className="text-center font-heading text-lg font-bold text-brand-text mb-2">{tier.quantity}x {BRAND.name_with_tm}</p>
                <div className="text-center mb-3">
                  <div className="font-heading text-3xl font-bold text-brand-text">{fmtMoney(total)}</div>
                  <div className="text-sm text-brand-text-light line-through">{fmtMoney(orig)}</div>
                  <div className="text-xs text-brand-primary font-semibold mt-1">{fmtMoney(per)} per bottle</div>
                </div>
                <div className="bg-brand-bg border border-brand-primary/30 rounded text-center text-xs font-semibold text-brand-primary-dark px-3 py-2 mb-3">
                  {tier.cta_text}
                </div>
                {tier.bonus_text && (
                  <p className="text-[11px] text-brand-gold-dark font-semibold text-center mb-3 leading-tight">{tier.bonus_text}</p>
                )}
                <p className="text-[11px] text-center text-brand-text-light mb-4">{tier.shipping_text}</p>
                <button className="mt-auto w-full bg-brand-primary hover:bg-brand-text text-white font-bold py-3 rounded-lg transition-all hover:shadow-lg">
                  {tier.button_text}
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </section>
  );
}

