function GuaranteeSeal() {
  return (
    <svg viewBox="0 0 200 200" width="180" height="180" xmlns="http://www.w3.org/2000/svg">
      <defs>
        <path id="curve-top" d="M 30 100 A 70 70 0 0 1 170 100" fill="none" />
        <path id="curve-bottom" d="M 30 100 A 70 70 0 0 0 170 100" fill="none" />
      </defs>
      <g fill={BRAND.palette.accent_gold_dark}>
        {Array.from({ length: 32 }).map((_, i) => {
          const angle = (i * 360) / 32;
          const rad = (angle * Math.PI) / 180;
          const x = 100 + 95 * Math.cos(rad);
          const y = 100 + 95 * Math.sin(rad);
          return <circle key={i} cx={x} cy={y} r="5" />;
        })}
      </g>
      <circle cx="100" cy="100" r="88" fill={BRAND.palette.accent_gold_dark} />
      <circle cx="100" cy="100" r="82" fill="none" stroke={BRAND.palette.background} strokeWidth="1.5" opacity="0.4" />
      <circle cx="100" cy="100" r="74" fill="none" stroke={BRAND.palette.background} strokeWidth="0.8" opacity="0.3" />
      <text fill={BRAND.palette.background} fontFamily="Playfair Display, serif" fontSize="12" fontWeight="700" letterSpacing="4">
        <textPath href="#curve-top" startOffset="50%" textAnchor="middle">GUARANTEE</textPath>
      </text>
      <text x="100" y="108" fill={BRAND.palette.background} fontFamily="Playfair Display, serif" fontSize="38" fontWeight="900" textAnchor="middle">100%</text>
      <text fill={BRAND.palette.background} fontFamily="Playfair Display, serif" fontSize="11" fontWeight="700" letterSpacing="3">
        <textPath href="#curve-bottom" startOffset="50%" textAnchor="middle">MONEY BACK</textPath>
      </text>
    </svg>
  );
}

